// @kern-source: prompt-input:25
function isMouseReportInput(input: string): boolean {
  if (!input) {
    return false;
  }
  if (/\x1b\[<\d+;\d+;\d+[mM]/.test(input)) {
    return true;
  }
  if (/\[<\d+;\d+;\d+[mM]/.test(input)) {
    return true;
  }
  if (/^<\d+;\d+;\d+[mM]$/.test(input)) {
    return true;
  }
  if (/^\[<\d+;\d+;\d+[mM]$/.test(input)) {
    return true;
  }
  if (/^(?:\x1b\[)?<\d+;\d+;\d*$/.test(input)) {
    return true;
  }
  if (/^(?:\x1b\[|\[)?<\d+;\d+;\d*$/.test(input)) {
    return true;
  }
  return false;
}

// @kern-source: prompt-input:43
function stripMouseReportInput(input: string): string {
  if (!input) {
    return input;
  }
  return input.replace(/\x1b\[<\d+;\d+;\d+[mM]/g, '').replace(/\[<\d+;\d+;\d+[mM]/g, '').replace(/(?:\x1b\[|\[)?<\d+;\d+;\d*(?:[mM])?/g, '');
}

