export function wrapPromptText(value: string, width: number): string[] {
  const safeWidth = Math.max(1, width);
  const lines = [''];
  let col = 0;
  for (const char of value) {
    if (char === '\n') {
      lines.push('');
      col = 0;
      continue;
    }
    if (col === safeWidth) {
      lines.push('');
      col = 0;
    }
    lines[lines.length - 1] += char;
    col += 1;
  }
  return lines;
}

